//! Compile-time prompt templates for the Loom workflow phases.
//!
//! Each template family lives in its own submodule; the `Template` impls are
//! generated by Askama (`#[derive(Template)]`) and validated at build time â€”
//! a missing context field is a compile error.
//!
//! Agent-generated content (`previous_failure`, `title`, `description`,
//! `existing_tasks`) is wrapped in `<agent-output>...</agent-output>` markers
//! in the template bodies as a best-effort prompt-injection mitigation.
//!
//! # Public Contract
//!
//! `templates` is a public-contract crate. External Rust consumers
//! (e.g. RAG pipelines, domain-specific review tools) compose their own
//! templates from the exposed typed building blocks
//! ([`PinnedContext`], [`PreviousFailure`], [`LoopContext`],
//! [`ReviewContext`]) and the `PARTIAL_*` partial-string constants
//! below. Loom's own workflow templates (`plan_*`, `todo_*`, `run`,
//! `review`, `msg`) are internal â€” consumers compose with the partials
//! and typed contexts, not with the workflow shells.

pub mod criterion_status;
pub mod finding;
pub mod msg;
pub mod plan;
pub mod previous_failure;
pub mod review;
pub mod run;
pub mod todo;

pub use criterion_status::{CriterionResult, CriterionStatus};
pub use finding::{
    ConcernToken, Finding, FindingParseError, FindingTarget, FindingValidator, LOOM_FINDING_PREFIX,
    TargetKind,
};
pub use msg::{ClarifyBead, ClarifyOption, MsgContext};
pub use plan::{PlanNewContext, PlanUpdateContext};
pub use previous_failure::{
    BadWalk, DriverNoticeCause, PREVIOUS_FAILURE_MAX_LEN, PreviousFailure, STDERR_TAIL_PER_BLOCK,
    VerifierFailure,
};
pub use review::{ReviewContext, ReviewSource};
pub use run::LoopContext;
pub use todo::{TodoNewContext, TodoUpdateContext};

/// Project-overview + style-rules pinning shape, exposed as a typed
/// building block external consumers can embed in their own template
/// contexts to mirror Loom's pinning ergonomics without re-deriving the
/// field names.
///
/// `pinned_context` is the project-overview body (`docs/README.md` by
/// default in Loom's binary); `style_rules` is the style-rules document
/// body (`docs/style-rules.md` by default). Both arrive pre-rendered â€”
/// the template engine treats them as opaque strings.
#[derive(Debug, Clone)]
pub struct PinnedContext {
    pub pinned_context: String,
    pub style_rules: String,
}

